path = '/Users/dennisphilipjohnson/Downloads/my-reading-room/templates/utilities.html'
old = open(path).read()
old_snippet = '    <form class="import-form" action="/utilities/enrich" method="POST" enctype="multipart/form-data">'
new_snippet = '    <form class="import-form" action="/utilities/enrich" method="POST" enctype="multipart/form-data" id="enrichForm">\n      <input type="text" name="api_key" class="api-key-input" placeholder="Paste your Google Books API key first\u2026" autocomplete="off" style="width:100%;padding:12px 16px;margin-bottom:10px;background:#2a2a2a;border:1px solid #555;border-radius:10px;color:#f0ede8;font-size:0.85rem;outline:none;">'
result = old.replace(old_snippet, new_snippet, 1).replace('onclick="this.querySelector(\'input[type=file]\').click()"', 'onclick="submitEnrich()"', 1).replace('onchange="document.getElementById(\'spinnerOverlay\').classList.add(\'active\'); this.closest(\'form\').submit()"', 'id="enrichFileInput"', 1).replace('</body>', '  <script>\n    function submitEnrich() {\n      var k = document.querySelector(\'#enrichForm input[name="api_key"]\').value.trim();\n      if (!k) { alert(\'Please paste your Google Books API key first.\'); return; }\n      var fi = document.getElementById(\'enrichFileInput\');\n      fi.onchange = function() { if (fi.files.length > 0) { document.getElementById(\'spinnerOverlay\').classList.add(\'active\'); document.getElementById(\'enrichForm\').submit(); } };\n      fi.click();\n    }\n  </script>\n</body>', 1)
open(path, 'w').write(result)
print('Done! enrichForm present:', 'enrichForm' in result)
